+    #[test]
+    fn test_prepare_select_from_attached_schema_uses_deferred_dispatch() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, value TEXT);")
+            .unwrap();
+        conn.execute("ATTACH DATABASE ':memory:' AS aux;").unwrap();
+        conn.execute("CREATE TABLE aux.t (id INTEGER PRIMARY KEY, value TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO t VALUES (1, 'main-row');")
+            .unwrap();
+        conn.execute("INSERT INTO aux.t VALUES (1, 'aux-row');")
+            .unwrap();
+
+        let stmt = conn
+            .prepare("SELECT value FROM aux.t ORDER BY id;")
+            .unwrap();
+        assert!(
+            stmt.deferred_query_statement.is_some(),
+            "attached-schema SELECT should defer execution so the schema prefix routes to the attached connection"
+        );
+        assert!(
+            stmt.db.is_none(),
+            "attached-schema SELECT should not prebind the main MemDatabase"
+        );
+
+        let rows = stmt.query().unwrap();
+        assert_eq!(
+            rows.iter()
+                .map(|row| row.values()[0].clone())
+                .collect::<Vec<_>>(),
+            vec![SqliteValue::Text("aux-row".into())]
+        );
+    }
